// Helper function to get autopilot name from MAV_AUTOPILOT enum
static const char* get_autopilot_name(uint8_t autopilot) {
    switch (autopilot) {
        case 0: return "Generic";
        case 1: return "Reserved";
        case 2: return "SLUGS";
        case 3: return "ArduPilot";
        case 4: return "OpenPilot";
        case 5: return "Generic_W";
        case 6: return "PPZ";
        case 7: return "UDB";
        case 8: return "FlexiPilot";
        case 10: return "SMACCMPilot";
        case 11: return "AutoQuad";
        case 12: return "PX4";
        case 13: return "SMAVLink";
        case 14: return "SmartAP";
        case 15: return "Airware";
        case 16: return "Path_Pilot";
        default: return "Unknown";
    }
}

// Helper function to get system type name from MAV_TYPE enum
static const char* get_system_type_name(uint8_t type) {
    switch (type) {
        case 0: return "Generic";
        case 1: return "Fixed Wing";
        case 2: return "Quadrotor";
        case 3: return "Coaxial";
        case 4: return "Helicopter";
        case 5: return "Antenna Tracker";
        case 6: return "GCS";
        case 13: return "Hexarotor";
        case 14: return "Octorotor";
        case 15: return "Tricopter";
        case 20: return "VTOL";
        case 27: return "Rover";
        case 28: return "Boat";
        case 30: return "Submarine";
        default: return "Unknown";
    }
}
