static void modal_close_cb(lv_event_t *e) {
    lv_obj_t *modal = lv_event_get_current_target(e);
    lv_obj_del(modal);
}

static lv_obj_t* create_detail_modal(const char *title, const char *content) {
    lv_obj_t *modal = lv_obj_create(lv_scr_act());
    lv_obj_set_size(modal, 200, 180);
    lv_obj_center(modal);
    lv_obj_set_style_bg_color(modal, lv_color_hex(0x000000), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_bg_opa(modal, 255, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_border_width(modal, 0, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_radius(modal, 10, LV_PART_MAIN | LV_STATE_DEFAULT);
    
    lv_obj_t *title_label = lv_label_create(modal);
    lv_obj_set_style_text_font(title_label, &lv_font_montserrat_14, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_color(title_label, lv_color_hex(0x00ff00), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(title_label, title);
    lv_obj_align(title_label, LV_ALIGN_TOP_MID, 0, 10);
    
    lv_obj_t *content_label = lv_label_create(modal);
    lv_obj_set_style_text_font(content_label, &lv_font_montserrat_14, LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_obj_set_style_text_color(content_label, lv_color_hex(0xffffff), LV_PART_MAIN | LV_STATE_DEFAULT);
    lv_label_set_text(content_label, content);
    lv_obj_align(content_label, LV_ALIGN_TOP_LEFT, 10, 35);
    lv_label_set_long_mode(content_label, LV_LABEL_LONG_WRAP);
    lv_obj_set_width(content_label, 180);
    
    lv_obj_add_flag(modal, LV_OBJ_FLAG_CLICKABLE);
    lv_obj_add_event_cb(modal, modal_close_cb, LV_EVENT_CLICKED, NULL);
    
    lv_obj_clear_flag(title_label, LV_OBJ_FLAG_CLICKABLE);
    lv_obj_clear_flag(content_label, LV_OBJ_FLAG_CLICKABLE);
    lv_obj_add_flag(title_label, LV_OBJ_FLAG_EVENT_BUBBLE);
    lv_obj_add_flag(content_label, LV_OBJ_FLAG_EVENT_BUBBLE);
    
    return modal;
}



