static void mavlink_btn_click_cb(lv_event_t *e) {
    (void)e;
    char mavlink_text[300];
    
    if (mavlink_data.heartbeat_received) {
        if (mavlink_data.version_received) {
            sprintf(mavlink_text,
                "Status: %s\n"
                "Heartbeats: %u\n"
                "Battery: %.1fV %.1fA %d%%\n"
                "Connection: %s\n"
                "System: %s\n"
                "Type: %s\n"
                "FW: %08X | Board: %08X\n"
                "Vendor: %04X | Product: %04X\n"
                "MAVLink: v2.0\n"
                "CPU: %.1f°C | Errors: %u",
                mavlink_data.data_valid ? "Receiving" : "Waiting",
                (unsigned int)mavlink_data.heartbeat_count,
                mavlink_data.voltage, mavlink_data.current, mavlink_data.percent,
                mavlink_data.data_valid ? "OK" : "Waiting",
                get_autopilot_name(mavlink_data.autopilot_type),
                get_system_type_name(mavlink_data.system_type),
                mavlink_data.flight_sw_version,
                mavlink_data.board_version,
                mavlink_data.vendor_id,
                mavlink_data.product_id,
                mavlink_data.esp32_temperature,
                mavlink_data.errors_comm);
        } else {
            sprintf(mavlink_text,
                "Status: %s\n"
                "Heartbeats: %u\n"
                "Battery: %.1fV %.1fA %d%%\n"
                "Connection: %s\n"
                "System: %s\n"
                "Type: %s\n"
                "FW: Requesting...\n"
                "MAVLink: v2.0\n"
                "CPU: %.1f°C | Errors: %u",
                mavlink_data.data_valid ? "Receiving" : "Waiting",
                (unsigned int)mavlink_data.heartbeat_count,
                mavlink_data.voltage, mavlink_data.current, mavlink_data.percent,
                mavlink_data.data_valid ? "OK" : "Waiting",
                get_autopilot_name(mavlink_data.autopilot_type),
                get_system_type_name(mavlink_data.system_type),
                mavlink_data.esp32_temperature,
                mavlink_data.errors_comm);
        }
    } else {
        sprintf(mavlink_text,
            "Status: Waiting...\n"
            "Heartbeats: 0\n"
            "Battery: --\n"
            "Connection: --\n"
            "System: --\n"
            "Type: --\n"
            "MAVLink: v2.0\n"
            "\nCheck cable D2 (RX)");
    }
    
    create_detail_modal("MAVLink Details", mavlink_text);
}


static void battery_btn_click_cb(lv_event_t *e) {
    (void)e;
    char battery_text[300];
    
    if (mavlink_data.data_valid) {
        // Calculate flight time from time_remaining
        int hours = mavlink_data.time_remaining / 3600;
        int mins = (mavlink_data.time_remaining % 3600) / 60;
        
        // Build cell voltages string
        char cells_str[100] = "";
        for (int i = 0; i < mavlink_data.cell_count && i < 6; i++) {
            char cell[20];
            sprintf(cell, "C%d:%.2fV ", i+1, mavlink_data.cell_voltages[i] / 1000.0);
            strcat(cells_str, cell);
        }
        
        // Build temperature string
        char temp_str[20];
        if (mavlink_data.temperature == 0) {
            strcpy(temp_str, "--");
        } else {
            sprintf(temp_str, "%.1fC", mavlink_data.temperature / 100.0);
        }
        
        sprintf(battery_text,
            "Battery: %s\n"
            "Voltage: %.2fV (%dS)\n"
            "Current: %.2fA\n"
            "Remaining: %d%%\n"
            "Flight Time: %02d:%02d\n"
            "Temp: %s\n"
            "Cells: %s",
            mavlink_data.percent > 20 ? "OK" : "LOW",
            mavlink_data.voltage,
            mavlink_data.cell_count,
            mavlink_data.current,
            mavlink_data.percent,
            hours, mins,
            temp_str,
            cells_str[0] ? cells_str : "N/A");
    } else {
        sprintf(battery_text,
            "Battery: --\n"
            "Voltage: --\n"
            "Current: --\n"
            "Remaining: --\n"
            "Flight Time: --\n"
            "Temp: --\n"
            "Waiting for MAVLink data...");
    }
    
    create_detail_modal("Battery Details", battery_text);
}

static void system_btn_click_cb(lv_event_t *e) {
    (void)e;
    char system_text[400];
    
    // Get uptime in seconds
    unsigned long uptime_s = millis() / 1000;
    int up_h = uptime_s / 3600;
    int up_m = (uptime_s % 3600) / 60;
    int up_s = uptime_s % 60;
    
    // Build temperature strings for MAVLink sensors
    char imu_temp_str[20] = "--";
    char press_temp_str[20] = "--";
    if (mavlink_data.temperature_imu != 0) {
        sprintf(imu_temp_str, "%.1fC", mavlink_data.temperature_imu / 100.0);
    }
    if (mavlink_data.temperature_press != 0) {
        sprintf(press_temp_str, "%.1fC", mavlink_data.temperature_press / 100.0);
    }
    
    sprintf(system_text,
        "Disp.Temp: %.1fC\n"
        "IMU Temp: %s\n"
        "Press Temp: %s\n"
        "CPU Load: %d%%\n"
        "Errors: %d\n"
        "Uptime: %02d:%02d:%02d\n"
        "Ver: v.0.1",
        mavlink_data.esp32_temperature,
        imu_temp_str,
        press_temp_str,
        mavlink_data.load,
        mavlink_data.errors_comm,
        up_h, up_m, up_s);
    
    create_detail_modal("System Status", system_text);
}

