// Toggle between Menu and GPS display on Screen3
static void ui_Screen3_switch_mode(bool gps_mode) {
    ui_Screen3_GPS_Mode = gps_mode;
    if (gps_mode) {
        // Show GPS panel, hide menu panel
        if (ui_Panel3) lv_obj_add_flag(ui_Panel3, LV_OBJ_FLAG_HIDDEN);
        if (ui_Screen3_GPS_Panel) lv_obj_clear_flag(ui_Screen3_GPS_Panel, LV_OBJ_FLAG_HIDDEN);
        if (ui_Screen3_ToggleBtn) lv_label_set_text(lv_obj_get_child(ui_Screen3_ToggleBtn, 0), "MENU");
    } else {
        // Show menu, hide GPS
        if (ui_Panel3) lv_obj_clear_flag(ui_Panel3, LV_OBJ_FLAG_HIDDEN);
        if (ui_Screen3_GPS_Panel) lv_obj_add_flag(ui_Screen3_GPS_Panel, LV_OBJ_FLAG_HIDDEN);
        if (ui_Screen3_ToggleBtn) lv_label_set_text(lv_obj_get_child(ui_Screen3_ToggleBtn, 0), "GPS");
    }
}

// Toggle button callback
static void ui_Screen3_toggle_cb(lv_event_t *e) {
    (void)e;
    ui_Screen3_switch_mode(!ui_Screen3_GPS_Mode);
}

// GPS panel click callback - close when clicked
static void ui_Screen3_gps_panel_click_cb(lv_event_t *e) {
    (void)e;
    // Close GPS panel and return to menu
    ui_Screen3_switch_mode(false);
}

// Update GPS display on Screen3
void update_screen3_gps(int32_t lat, int32_t lon, int32_t alt, uint8_t satellites, uint8_t fix_type) {
    // Only update if GPS panel exists
    if (!ui_Screen3_GPS_Lat || !ui_Screen3_GPS_Lon || !ui_Screen3_GPS_Alt) return;
    
    char buf[32];
    
    // Format latitude (degrees * 1e7)
    float lat_deg = lat / 1e7f;
    sprintf(buf, "Lat: %.6f", lat_deg);
    lv_label_set_text(ui_Screen3_GPS_Lat, buf);
    
    // Format longitude (degrees * 1e7)
    float lon_deg = lon / 1e7f;
    sprintf(buf, "Lon: %.6f", lon_deg);
    lv_label_set_text(ui_Screen3_GPS_Lon, buf);
    
    // Format altitude (mm to m)
    int alt_m = alt / 1000;
    sprintf(buf, "Alt: %d m", alt_m);
    lv_label_set_text(ui_Screen3_GPS_Alt, buf);
    
    // Satellites
    sprintf(buf, "Sats: %d", satellites);
    lv_label_set_text(ui_Screen3_GPS_Sats, buf);
    
    // Fix type with color coding
    const char* fix_str;
    lv_color_t fix_color;
    switch (fix_type) {
        case 0:
        case 1:
            fix_str = "No GPS";
            fix_color = lv_color_hex(0xFF0000);  // Red
            break;
        case 2:
            fix_str = "2D Fix";
            fix_color = lv_color_hex(0xFFFF00);  // Yellow
            break;
        case 3:
            fix_str = "3D Fix";
            fix_color = lv_color_hex(0x00FF00);  // Green
            break;
        default:
            fix_str = "Unknown";
            fix_color = lv_color_hex(0x808080);  // Gray
    }
    lv_label_set_text(ui_Screen3_GPS_Fix, fix_str);
    lv_obj_set_style_text_color(ui_Screen3_GPS_Fix, fix_color, LV_PART_MAIN);
}

