    lv_obj_add_flag(ui_Screen3_GPS_Panel, LV_OBJ_FLAG_HIDDEN);
    lv_obj_clear_flag(ui_Screen3_GPS_Panel, LV_OBJ_FLAG_SCROLLABLE);

    // GPS Title
